import{_ as e,o as a,c as i,ae as r}from"./chunks/framework.B6gjLfeO.js";const b=JSON.parse('{"title":"Journeys Image Recommendations","description":"","frontmatter":{"title":"Journeys Image Recommendations","slug":"journeys-image-recommendations"},"headers":[],"relativePath":"marketer-hub/journeys-image-recommendations.md","filePath":"marketer-hub/journeys-image-recommendations.md"}'),d={name:"marketer-hub/journeys-image-recommendations.md"};function o(n,t,h,l,m,s){return a(),i("div",null,[...t[0]||(t[0]=[r('<p>Journeys are hugely successful at bringing mobile web users into your apps. But to be most effective, the Journey needs to look great and fit well on the page. The difficulty here is that Journeys can come in a wide variety of shapes and sizes but this guide should help you make some sizing decisions for a few of the most requested Journeys Templates.</p><h2 id="image-format-compatibility" tabindex="-1">Image Format Compatibility <a class="header-anchor" href="#image-format-compatibility" aria-label="Permalink to &quot;Image Format Compatibility&quot;">​</a></h2><p>The following formats are compatible with Journeys creatives:</p><ul><li>jpeg</li><li>png</li><li>gif</li><li>pdf</li><li>mp4</li><li>mov</li></ul><h2 id="full-page-image" tabindex="-1">Full Page Image <a class="header-anchor" href="#full-page-image" aria-label="Permalink to &quot;Full Page Image&quot;">​</a></h2><p>The Full Page Journey is a bit tricky because the template itself is responsive to the dimensions of the phone. To account for these potentially changing dimensions, some bleed must be built into the images in use.</p><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>Background position</td><td>center</td></tr><tr><td>Background size</td><td>cover</td></tr><tr><td>Dimensions</td><td>512x1024px</td></tr><tr><td>Main content area</td><td>414x736px</td></tr></tbody></table><p><em>[Image: 514]</em></p><h2 id="partial-page-image" tabindex="-1">Partial Page Image <a class="header-anchor" href="#partial-page-image" aria-label="Permalink to &quot;Partial Page Image&quot;">​</a></h2><p>The Partial Page Journey can be a little easier to account for because the template itself is responsive to the dimensions of only the width if desired or as a percentage of the view height. To account for these potentially changing dimensions, some bleed must be built into the images in use.</p><h3 id="fixed-height" tabindex="-1">Fixed Height <a class="header-anchor" href="#fixed-height" aria-label="Permalink to &quot;Fixed Height&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>Background position</td><td>Center</td></tr><tr><td>Background size</td><td>Cover</td></tr><tr><td>Example Dimensions</td><td>512x321px</td></tr><tr><td>Main Content Area</td><td>350x321px</td></tr></tbody></table><p><em>[Image: 1366]</em></p><h3 id="variable-height-33-view-height-top" tabindex="-1">Variable Height (33% View Height) - Top <a class="header-anchor" href="#variable-height-33-view-height-top" aria-label="Permalink to &quot;Variable Height (33% View Height) - Top&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>Background Position</td><td>Top Center</td></tr><tr><td>Background Size</td><td>Cover</td></tr><tr><td>Example Dimensions</td><td>512x321px</td></tr><tr><td>Main Content Area</td><td>414x250px</td></tr></tbody></table><p><em>[Image: 1366]</em></p><h3 id="variable-height-33-view-height-bottom" tabindex="-1">Variable Height (33% View Height) - Bottom <a class="header-anchor" href="#variable-height-33-view-height-bottom" aria-label="Permalink to &quot;Variable Height (33% View Height) - Bottom&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th></th></tr></thead><tbody><tr><td>Background Position</td><td>Bottom Center</td></tr><tr><td>Background Size</td><td>Cover</td></tr><tr><td>Example Dimensions</td><td>512x321px</td></tr><tr><td>Main Content Area</td><td>414x250px</td></tr></tbody></table><h2 id="app-icon-image" tabindex="-1">App Icon Image <a class="header-anchor" href="#app-icon-image" aria-label="Permalink to &quot;App Icon Image&quot;">​</a></h2><p>Recommended sizing: 180x180px</p><h2 id="interstitial-6" tabindex="-1">Interstitial 6 <a class="header-anchor" href="#interstitial-6" aria-label="Permalink to &quot;Interstitial 6&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Minimum Size</th></tr></thead><tbody><tr><td>Background Image Size</td><td>410 x 732px</td></tr><tr><td>App Icon Size</td><td>78 x 40px</td></tr><tr><td>App Banner Size</td><td>n/a</td></tr></tbody></table><h2 id="banner-tall-banner-bottom-1" tabindex="-1">Banner Tall Banner Bottom 1 <a class="header-anchor" href="#banner-tall-banner-bottom-1" aria-label="Permalink to &quot;Banner Tall Banner Bottom 1&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Minimum Size</th></tr></thead><tbody><tr><td>Background Image Size</td><td>410 x 343px</td></tr><tr><td>App Icon Size</td><td>n/a</td></tr><tr><td>App Banner Size</td><td>410 x 151px</td></tr></tbody></table><h2 id="banner-tall-banner-top-4" tabindex="-1">Banner Tall Banner Top 4 <a class="header-anchor" href="#banner-tall-banner-top-4" aria-label="Permalink to &quot;Banner Tall Banner Top 4&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Minimum Size</th></tr></thead><tbody><tr><td>Background Image Size</td><td>375 x 360px</td></tr><tr><td>App Icon Size</td><td>n/a</td></tr><tr><td>App Banner Size</td><td>375 x 151px</td></tr></tbody></table><h2 id="template-3" tabindex="-1">Template 3 <a class="header-anchor" href="#template-3" aria-label="Permalink to &quot;Template 3&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Minimum Size</th></tr></thead><tbody><tr><td>Background Image Size</td><td>375 x 176px</td></tr><tr><td>App Icon Size</td><td>63 x 63px</td></tr><tr><td>App Banner Size</td><td>n/a</td></tr></tbody></table><h2 id="template-4" tabindex="-1">Template 4 <a class="header-anchor" href="#template-4" aria-label="Permalink to &quot;Template 4&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>Minimum Size</th></tr></thead><tbody><tr><td>Background Image Size</td><td>410 x 732px</td></tr><tr><td>App Icon Size</td><td>63 x 63px</td></tr><tr><td>App Banner Size</td><td>n/a</td></tr></tbody></table>',30)])])}const g=e(d,[["render",o]]);export{b as __pageData,g as default};
